import{_ as a,o as i,c as n,ai as e}from"./chunks/framework.ampVZV4B.js";const g=JSON.parse('{"title":"场景实战：多线程与并发问题调优","description":"","frontmatter":{},"headers":[],"relativePath":"java/concurrency-scenario.md","filePath":"java/concurrency-scenario.md"}'),t={name:"java/concurrency-scenario.md"};function l(r,s,o,p,d,c){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="场景实战-多线程与并发问题调优" tabindex="-1">场景实战：多线程与并发问题调优 <a class="header-anchor" href="#场景实战-多线程与并发问题调优" aria-label="Permalink to “场景实战：多线程与并发问题调优”">​</a></h1><hr><h3 id="❓-面试实战-你们系统中哪里用到了多线程-怎么用的" tabindex="-1">❓ 面试实战：你们系统中哪里用到了多线程？怎么用的？ <a class="header-anchor" href="#❓-面试实战-你们系统中哪里用到了多线程-怎么用的" aria-label="Permalink to “❓ 面试实战：你们系统中哪里用到了多线程？怎么用的？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 我们在<strong>“耗时任务异步化”</strong>和<strong>“多接口并行聚合查询”</strong>这两个高频场景中大量使用了多线程（线程池），将接口响应时间从秒级压缩到了百毫秒级。</p><p><strong>📝 详细业务场景落地（面试高分答题模板）：</strong></p><p><strong>场景一：耗时任务异步化（提升主流程响应速度）</strong></p><ul><li><strong>业务痛点</strong>：用户注册/下单成功后，系统需要：1. 写入数据库；2. 发送成功短信；3. 发送新用户优惠券；4. 记录操作日志。如果串行执行，整个接口可能要耗时 2~3 秒，用户体验极差（一直在转圈圈）。</li><li><strong>实战做法</strong>： <ul><li>核心主流程（写库）依然同步执行，耗时 50ms。</li><li>非核心流程（发短信、发券、写日志），直接封装成 <code>Runnable</code> 或 <code>Callable</code> 任务，<strong>扔给自定义的业务异步线程池（如 <code>AsyncEventThreadPool</code>）去后台默默执行</strong>。</li><li>主线程不用等它们执行完，直接返回“注册成功”。接口耗时瞬间降到 50ms。</li></ul></li><li><strong>坑点防范</strong>：如果线程池满了或者服务器突然宕机，这些扔在内存队列里的异步任务会丢失。因此对于极度重要的非核心任务（如发券），我们最终会改用 <strong>MQ（消息队列）</strong> 来替代本地多线程，保证消息持久化不丢失。</li></ul><p><strong>场景二：多接口并行聚合查询（CountDownLatch/CompletableFuture）</strong></p><ul><li><strong>业务痛点</strong>：在“App 首页”或者“商品详情页”，前端调用我们一个接口，但后端需要去组装大量数据。比如查商品信息（200ms）、查店铺信息（100ms）、查商品评价（150ms）、查用户浏览历史（100ms）。串行查完总共需要 <code>200+100+150+100 = 550ms</code>。</li><li><strong>实战做法</strong>： <ul><li>我们使用了 JDK 8 的 <strong><code>CompletableFuture</code></strong> 进行多线程编排。</li><li>将这 4 个查询任务分别提交给线程池<strong>并行执行</strong>。</li><li>使用 <code>CompletableFuture.allOf(f1, f2, f3, f4).join()</code> 阻塞等待所有任务全部完成。</li><li><strong>最终耗时</strong>：取决于最慢的那个任务（即 200ms），性能直接提升了一倍多！</li></ul></li></ul><hr><h3 id="❓-面试实战-线上如果出现了-cpu-100-或者线程死锁-你怎么排查定位-【高级】" tabindex="-1">❓ 面试实战：线上如果出现了 CPU 100% 或者线程死锁，你怎么排查定位？【高级】 <a class="header-anchor" href="#❓-面试实战-线上如果出现了-cpu-100-或者线程死锁-你怎么排查定位-【高级】" aria-label="Permalink to “❓ 面试实战：线上如果出现了 CPU 100% 或者线程死锁，你怎么排查定位？【高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li><strong>排查 CPU 100%</strong>：使用 <code>top</code> 命令找到最耗 CPU 的<strong>进程 PID</strong> -&gt; 用 <code>top -Hp</code> 找到该进程下最耗 CPU 的<strong>线程 ID</strong> -&gt; 把线程 ID 转成<strong>16进制</strong> -&gt; 用 <code>jstack</code> 导出线程快照，搜索该 16 进制定位到具体的 <strong>Java 代码行数</strong>（通常是写了死循环或者频繁 Full GC）。</li><li><strong>排查死锁</strong>：直接使用 <code>jstack</code> 或者 JDK 自带的 <code>jconsole / jvisualvm</code>，工具会自动帮你检测并在日志最后打印出 <code>Found one Java-level deadlock</code>。</li></ul><p><strong>📝 详细排查命令实操（死记硬背，面试必考）：</strong></p><p><strong>第一题：排查 CPU 飙高</strong></p><ol><li>找出最耗 CPU 的进程 ID（假设是 10086）：<div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">top</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>查看这个进程内部，哪个线程最耗 CPU（假设是 10090）：<div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">top</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10086</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>将十进制的线程 ID (10090) 转换成十六进制（假设结果是 <code>276a</code>）：<div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;%x\\n&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10090</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>绝杀：使用 <code>jstack</code> 打印堆栈日志，并 <code>grep</code> 搜索这个十六进制的线程号：<div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jstack</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10086</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;276a&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><strong>结果</strong>：终端会直接打印出这个线程正在执行的堆栈信息，你一眼就能看出是哪个类、哪一行的 <code>while(true)</code> 代码导致了 CPU 狂飙，或者看到是 <code>VM Thread</code> 正在疯狂做垃圾回收。</li></ol><p><strong>第二题：排查死锁（Deadlock）</strong></p><ul><li><strong>死锁产生的四个必要条件</strong>：互斥、请求与保持、不剥夺、循环等待。我们写代码最容易犯的就是<strong>循环等待</strong>（A 拿了锁 1 等锁 2，B 拿了锁 2 等锁 1）。</li><li><strong>排查方法</strong>：直接执行 <code>jstack 进程号</code>，滑到日志的最底部。JVM 非常智能，它会明确告诉你：<div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Found one Java-level deadlock:</span></span>
<span class="line"><span>=============================</span></span>
<span class="line"><span>&quot;Thread-A&quot;:</span></span>
<span class="line"><span>  waiting to lock monitor 0x0000... (object 2),</span></span>
<span class="line"><span>  which is held by &quot;Thread-B&quot;</span></span>
<span class="line"><span>&quot;Thread-B&quot;:</span></span>
<span class="line"><span>  waiting to lock monitor 0x0000... (object 1),</span></span>
<span class="line"><span>  which is held by &quot;Thread-A&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div>根据日志提示的代码行数，去修改加锁的顺序即可解决。</li></ul><p><strong>🌟 面试加分项（现代化工具）：</strong> &quot;当然，在现代企业级开发中，我们如果再去敲那一堆 Linux 命令行就有点过时了。我们线上通常会部署 <strong>Alibaba Arthas（阿尔萨斯）</strong> 诊断工具。 排查 CPU 100% 只需要敲一行命令：<code>thread -n 3</code>，它就会直接打印出当前最忙的 3 个线程的堆栈和耗费 CPU 的具体行数。 排查死锁也只需要一行命令：<code>thread -b</code>，瞬间揪出造成阻塞的罪魁祸首。&quot;</p>`,21)])])}const k=a(t,[["render",l]]);export{g as __pageData,k as default};
